// Time:  O(n*l + m*L), m is the number of puzzles, L is the length of puzzles
//                    , n is the number of words, l is the max length of words
// Space: O(L!)

class Solution {    
public:
    vector<int> findNumOfValidWords(vector<string>& words, vector<string>& puzzles) {
        static const int L = 7;
        TrieNode trie;
        for (const auto& word : words) {
            vector<int> count(26);
            for (const auto& c: word) {
                count[c - 'a'] = 1;
            }
            const auto& total = accumulate(count.cbegin(), count.cend(), 0);
            if (total > L) {
                continue;
            }
            trie.insert(count);
        }
        vector<int> result;
        for (auto puzzle: puzzles) {
            const auto first = puzzle[0];
            sort(puzzle.begin(), puzzle.end());
            result.emplace_back(search(&trie, puzzle, 0, first, false));
        }
        return result;
    }

private:
    struct TrieNode;

    int search(TrieNode* node, const string& puzzle, int start, char first, bool met_first) {
        int result = 0;
        if (met_first) {
            result += node->end_count;
        }
        for (int i = start; i < puzzle.length(); ++i) {
            if (node->children[puzzle[i] - 'a'] == nullptr) {
                continue;
            }
            result += search(node->children[puzzle[i] - 'a'], puzzle, i + 1,
                             first, met_first || (puzzle[i] == first));
        }
        return result;
    }

    struct TrieNode {
        int end_count;
        vector<TrieNode *> children;

        TrieNode() : end_count{0}, children(26) {}

        void insert(const vector<int>& count) {
            auto* p = this;
            for (int i = 0; i < count.size(); ++i) {
                if (!count[i]) {
                    continue;
                }
                if (!p->children[i]) {
                    p->children[i] = new TrieNode;
                }
                p = p->children[i];
            }
            ++p->end_count;
        }

        ~TrieNode() {
            for (auto& node : children) {
                if (node) {
                    delete node;
                }
            }
        }
    };
};

// Time:  O(m*2^(L-1) + n*(l+m)), m is the number of puzzles, L is the length of puzzles
//                              , n is the number of words, l is the max length of words
// Space: O(m*2^(L-1))
class Solution2 {
public:
    vector<int> findNumOfValidWords(vector<string>& words, vector<string>& puzzles) {
        static const int L = 7;
        unordered_map<int, vector<int>> lookup;
        for (int i = 0; i < puzzles.size(); ++i) {
            vector<int> bits;
            const auto& base = 1 << (puzzles[i][0] - 'a');
            for (int j = 1; j < L; ++j) {
                bits.emplace_back(puzzles[i][j] - 'a');
            }
            for (int k = 0; k < 1 << bits.size(); ++k) {
                int bitset = base;
                for (int j = 0; j < bits.size(); ++j) {
                    if (k & (1 << j)) {
                        bitset |= 1 << bits[j];
                    }
                }
                lookup[bitset].emplace_back(i);
            }
        }
        vector<int> result(puzzles.size());
        for (const auto& word : words) {
            int bitset = 0;
            for (const auto& c : word) {
                bitset |= 1 << (c - 'a');
            }            
            if (!lookup.count(bitset)) {
                continue;
            }
            for (const auto& i : lookup[bitset]) {
                ++result[i];
            }
        }
        return result;
    }
};

# Time:  O(n*l + m*L), m is the number of puzzles, L is the length of puzzles
#                    , n is the number of words, l is the max length of words
# Space: O(L!)

class Solution(object):
    def findNumOfValidWords(self, words, puzzles):
        """
        :type words: List[str]
        :type puzzles: List[str]
        :rtype: List[int]
        """
        L = 7
        def search(node, puzzle, start, first, met_first):
            result = 0
            if "_end" in node and met_first:
                result += node["_end"]
            for i in xrange(start, len(puzzle)):
                if puzzle[i] not in node:
                    continue
                result += search(node[puzzle[i]], puzzle, i+1,
                                 first, met_first or (puzzle[i] == first))
            return result

        _trie = lambda: collections.defaultdict(_trie)
        trie = _trie()
        for word in words:
            count = set(word)
            if len(count) > L:
                continue
            word = sorted(count)
            end = reduce(dict.__getitem__, word, trie)
            end["_end"] = end["_end"]+1 if "_end" in end else 1
        result = []
        for puzzle in puzzles:
            first = puzzle[0]
            result.append(search(trie, sorted(puzzle), 0, first, False))
        return result


# Time:  O(m*2^(L-1) + n*(l+m)), m is the number of puzzles, L is the length of puzzles
#                              , n is the number of words, l is the max length of words
# Space: O(m*2^(L-1))
import collections


class Solution2(object):
    def findNumOfValidWords(self, words, puzzles):
        """
        :type words: List[str]
        :type puzzles: List[str]
        :rtype: List[int]
        """
        L = 7
        lookup = collections.defaultdict(list)
        for i in xrange(len(puzzles)):
            bits = []
            base = 1 << (ord(puzzles[i][0])-ord('a'))
            for j in xrange(1, L):
                bits.append(ord(puzzles[i][j])-ord('a'))
            for k in xrange(2**len(bits)):
                bitset = base
                for j in xrange(len(bits)):
                    if k & (1<<j):
                        bitset |= 1<<bits[j]
                lookup[bitset].append(i)
        result = [0]*len(puzzles)
        for word in words:
            bitset = 0
            for c in word:
                bitset |= 1<<(ord(c)-ord('a'))
            if bitset not in lookup:
                continue
            for i in lookup[bitset]:
                result[i] += 1
        return result
